"use client";

import { useSession, signIn, signOut } from "next-auth/react";
import { useState } from "react";
import axios from "axios";

export default function Home() {
  const { data: session, status } = useSession();
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState("");

  // 1. The Function that talks to your Python Backend
  const handleScan = async () => {
    // CHANGE THIS to your actual repository name!
    const repoName = "aman-mishra/test-repo"; 

    setLoading(true);
    setMessage(`🚀 Connecting to Python to scan ${repoName}...`);

    try {
      // Calls your Next.js API (web/app/api/scan/route.ts)
      const response = await axios.post("/api/scan", {
        repo_full_name: repoName
      });

      console.log("Python Response:", response.data);
      setMessage(`✅ Success! Engine says: ${response.data.message}`);
    } catch (error: any) {
      console.error("Scan Failed:", error);
      setMessage(`❌ Error: ${error.response?.data?.error || error.message}`);
    } finally {
      setLoading(false);
    }
  };

  // 2. Loading State (While checking if you are logged in)
  if (status === "loading") {
    return <div className="flex h-screen items-center justify-center bg-black text-white">Loading...</div>;
  }

  // 3. Not Logged In State (Show Login Button)
  if (!session) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-black text-white gap-6">
        <h1 className="text-4xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-purple-600">
          GitHelix
        </h1>
        <p className="text-gray-400">AI-Powered Repository Janitor</p>
        <button
          onClick={() => signIn("github")}
          className="px-8 py-3 bg-white text-black font-bold rounded-full hover:bg-gray-200 transition"
        >
          Sign in with GitHub
        </button>
      </div>
    );
  }

  // 4. Logged In State (Show Dashboard + Scan Button)
  return (
    <div className="flex flex-col min-h-screen bg-gray-900 text-white p-10">
      {/* Header */}
      <div className="flex justify-between items-center mb-12">
        <div className="flex items-center gap-4">
          <img 
            src={session.user?.image || ""} 
            className="w-12 h-12 rounded-full border-2 border-blue-500" 
            alt="Profile"
          />
          <div>
            <h2 className="text-xl font-bold">{session.user?.name}</h2>
            <p className="text-sm text-gray-400">Tech Executive @ MIT Manipal</p>
          </div>
        </div>
        <button 
          onClick={() => signOut()}
          className="px-4 py-2 text-sm bg-red-900/30 text-red-400 rounded hover:bg-red-900/50"
        >
          Sign Out
        </button>
      </div>

      {/* Main Action Card */}
      <div className="max-w-2xl mx-auto w-full bg-gray-800 rounded-xl p-8 border border-gray-700 shadow-2xl">
        <h1 className="text-2xl font-bold mb-6 flex items-center gap-2">
          🤖 Engine Control
        </h1>

        <div className="bg-black/50 p-4 rounded-lg font-mono text-sm mb-6 border border-gray-700">
          <p className="text-gray-400 mb-1">Target Repository:</p>
          <p className="text-green-400">aman-mishra/test-repo</p>
        </div>

        <button
          onClick={handleScan}
          disabled={loading}
          className={`w-full py-4 rounded-lg font-bold text-lg transition-all ${
            loading 
              ? "bg-gray-600 cursor-not-allowed" 
              : "bg-blue-600 hover:bg-blue-500 shadow-[0_0_20px_rgba(37,99,235,0.5)]"
          }`}
        >
          {loading ? "Scanning..." : "⚡ Scan Repository"}
        </button>

        {/* Status Message Area */}
        {message && (
          <div className={`mt-6 p-4 rounded-lg text-sm font-mono border ${
            message.includes("Error") ? "bg-red-900/20 border-red-500/50 text-red-200" 
            : "bg-green-900/20 border-green-500/50 text-green-200"
          }`}>
            {message}
          </div>
        )}
      </div>
    </div>
  );
}